// src/pages/About.js
import React, { useEffect, useMemo, useState } from "react";
import {
    Container,
    Box,
    Typography,
    Paper,
    Tabs,
    Tab,
    Stack,
    Divider,
    List,
    ListItem,
    ListItemIcon,
    ListItemText,
    Chip,
    Button,
    alpha,
    useTheme, Grow, Popper, ClickAwayListener,
} from "@mui/material";
import { motion } from "framer-motion";
import ImageSlideshow from "../components/ImageSlideshow";
import PdfGallery from "../components/PdfGallery";
import ExternalContentNotice from "../components/ExternalContentNotice";
import { useCookieConsent } from "../context/CookieConsentContext";
import {
    HistoryEdu,
    Groups,
    Badge,
    Savings,
    PhotoLibrary,
    Waves,
    CheckCircle,
    Person,
    School,
    Build,
} from "@mui/icons-material";

function PillTabs({ value, onChange, tabs }) {
    const theme = useTheme();
    return (
        <Box
            sx={{
                display: "flex",
                width: "100%",
                maxWidth: "100%",
                p: 0.6,
                borderRadius: 999,
                border: `1px solid ${alpha(theme.palette.text.primary, 0.10)}`,
                background: alpha("#fff", 0.75),
                backdropFilter: "blur(12px)",
                boxShadow: "0 14px 40px rgba(11,27,36,0.08)",
                overflow: "hidden",
            }}
        >
            <Tabs
                value={value}
                onChange={onChange}
                variant="scrollable"
                scrollButtons="auto"
                allowScrollButtonsMobile
                TabIndicatorProps={{ style: { display: "none" } }}
                sx={{
                    width: "100%",
                    minWidth: 0,
                    minHeight: 44,
                    "& .MuiTabs-scroller": {
                        overflowX: "auto !important",
                        WebkitOverflowScrolling: "touch",
                    },
                    "& .MuiTabs-flexContainer": { gap: 6, flexWrap: "nowrap" },
                }}
            >
                {tabs.map((t) => (
                    <Tab
                        key={t.key}
                        value={t.key}
                        label={t.label}
                        icon={t.icon}
                        iconPosition="start"
                        sx={{
                            minHeight: 44,
                            px: 1.6,
                            borderRadius: 999,
                            fontWeight: 750,
                            color: "text.primary",
                            "&.Mui-selected": {
                                color: "white",
                                background: `linear-gradient(135deg, ${theme.palette.primary.main}, ${theme.palette.secondary.main})`,
                                boxShadow: `0 14px 34px ${alpha(theme.palette.primary.main, 0.22)}`,
                            },
                        }}
                    />
                ))}
            </Tabs>
        </Box>
    );
}

function GlassCard({ children, sx }) {
    const theme = useTheme();
    return (
        <Paper
            component={motion.div}
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.55 }}
            elevation={0}
            sx={{
                p: { xs: 2.2, md: 3.2 },
                borderRadius: 3,
                background: alpha("#FFFFFF", 0.86),
                border: `1px solid ${alpha(theme.palette.text.primary, 0.10)}`,
                boxShadow: "0 18px 55px rgba(11,27,36,0.10)",
                backdropFilter: "blur(12px)",
                ...sx,
            }}
        >
            {children}
        </Paper>
    );
}

function BulletList({ items }) {
    return (
        <List dense sx={{ mt: 0.5 }}>
            {items.map((it, idx) => (
                <ListItem key={idx} sx={{ px: 0, py: 0.35 }}>
                    <ListItemIcon sx={{ minWidth: 34 }}>
                        <CheckCircle fontSize="small" />
                    </ListItemIcon>
                    <ListItemText
                        primary={it}
                        primaryTypographyProps={{ sx: { color: "text.secondary", lineHeight: 1.6 } }}
                    />
                </ListItem>
            ))}
        </List>
    );
}

export default function About() {
    const [content, setContent] = useState(null);
    const [error, setError] = useState("");
    const theme = useTheme();
    const { hasExternalConsent } = useCookieConsent();

    // Bilder-Mapping laden (wie Start.js)
    const [anspImages, setAnspImages] = useState({});

    useEffect(() => {
        fetch(process.env.PUBLIC_URL + "/content/about.json")
            .then((res) => {
                if (!res.ok) throw new Error(`HTTP ${res.status} beim Laden von /content/about.json`);
                return res.json();
            })
            .then(setContent)
            .catch((e) => setError(String(e)));
    }, []);

    useEffect(() => {
        fetch(process.env.PUBLIC_URL + "/resources/ansprechpartner/ansprechpartnerImages.json")
            .then((res) => (res.ok ? res.json() : {}))
            .then((data) => setAnspImages(data || {}))
            .catch(() => setAnspImages({}));
    }, []);

    const initialsFromName = (name) => {
        if (!name) return "?";
        const parts = String(name).trim().split(/\s+/).filter(Boolean);
        const a = parts[0]?.[0] || "?";
        const b = parts.length > 1 ? parts[parts.length - 1][0] : "";
        return (a + b).toUpperCase();
    };

    // macht Chips aus "TL***, Kinder-TL, Freediving-TL"
    const roleToChips = (role) => {
        if (!role) return [];
        const raw = String(role)
            .split(",")
            .map((x) => x.trim())
            .filter(Boolean);

        // optional: kleine Normalisierung (einheitlicher Gedankenstrich o.Ä. brauchst du nicht)
        return raw;
    };

    const AvatarCircle = ({ src, alt, size = 54, label, icon }) => {
        if (src) {
            return (
                <Box
                    sx={{
                        width: size,
                        height: size,
                        borderRadius: 999,
                        p: "2px",
                        background: `linear-gradient(135deg, ${alpha(theme.palette.primary.main, 0.9)}, ${alpha(
                            theme.palette.secondary.main,
                            0.9
                        )})`,
                        flex: "0 0 auto",
                    }}
                >
                    <Box
                        component="img"
                        src={src}
                        alt={alt}
                        loading="lazy"
                        sx={{
                            width: "100%",
                            height: "100%",
                            borderRadius: 999,
                            objectFit: "cover",
                            background: alpha("#000", 0.04),
                            border: `1px solid ${alpha("#fff", 0.7)}`,
                        }}
                    />
                </Box>
            );
        }

        return (
            <Box
                sx={{
                    width: size,
                    height: size,
                    borderRadius: 999,
                    display: "grid",
                    placeItems: "center",
                    background: alpha(theme.palette.primary.main, 0.08),
                    border: `1px solid ${alpha(theme.palette.primary.main, 0.16)}`,
                    flex: "0 0 auto",
                }}
            >
                {label ? (
                    <Typography sx={{ fontWeight: 950, letterSpacing: 0.5 }}>
                        {label}
                    </Typography>
                ) : (
                    icon || <Person />
                )}
            </Box>
        );
    };

    const slugify = (s) => {
        if (!s) return "";
        return String(s)
            .toLowerCase()
            .trim()
            .replace(/ä/g, "ae")
            .replace(/ö/g, "oe")
            .replace(/ü/g, "ue")
            .replace(/ß/g, "ss")
            .replace(/[^a-z0-9]+/g, "_")
            .replace(/^_+|_+$/g, "");
    };

    const anspImgUrl = (key) => {
        const file = anspImages?.[key];
        return file ? process.env.PUBLIC_URL + `/resources/ansprechpartner/${file}` : null;
    };

    const PersonCard = ({ name, role, imgKey, icon }) => {
        const [open, setOpen] = React.useState(false);
        const anchorRef = React.useRef(null);

        const src = imgKey ? anspImgUrl(imgKey) : null;
        const initials = initialsFromName(name);
        const chips = roleToChips(role);

        const toggle = () => setOpen((v) => !v);
        const close = () => setOpen(false);

        return (
            <ClickAwayListener onClickAway={close}>
                <Box sx={{ position: "relative" }}>
                    {/* Card */}
                    <Box
                        ref={anchorRef}
                        onClick={toggle}
                        role="button"
                        tabIndex={0}
                        onKeyDown={(e) => {
                            if (e.key === "Enter" || e.key === " ") toggle();
                            if (e.key === "Escape") close();
                        }}
                        sx={{
                            cursor: "pointer",
                            userSelect: "none",
                            p: 2.2,
                            borderRadius: 3,
                            border: `1px solid ${alpha(theme.palette.text.primary, 0.10)}`,
                            background: alpha("#fff", 0.65),
                            height: "100%",
                            transition: "transform 160ms ease, box-shadow 160ms ease, background 160ms ease",
                            "&:hover": {
                                transform: "translateY(-2px)",
                                boxShadow: "0 18px 45px rgba(11,27,36,0.10)",
                                background: alpha("#fff", 0.72),
                            },
                            outline: "none",
                        }}
                    >
                        <Stack direction="row" spacing={1.2} alignItems="center">
                            <AvatarCircle
                                src={src}
                                alt={name}
                                size={54}
                                label={!src ? initials : undefined}
                                icon={icon}
                            />

                            <Box sx={{ minWidth: 0, flex: 1 }}>
                                <Typography sx={{ fontWeight: 950, lineHeight: 1.15 }} noWrap>
                                    {name}
                                </Typography>

                                {/* role teaser: 2 Zeilen clamp */}
                                <Typography
                                    variant="body2"
                                    sx={{
                                        color: "text.secondary",
                                        lineHeight: 1.35,
                                        display: "-webkit-box",
                                        WebkitLineClamp: 2,
                                        WebkitBoxOrient: "vertical",
                                        overflow: "hidden",
                                    }}
                                >
                                    {role}
                                </Typography>
                            </Box>

                            {/* kleine Chevron */}
                            <Box
                                sx={{
                                    width: 34,
                                    height: 34,
                                    borderRadius: 999,
                                    display: "grid",
                                    placeItems: "center",
                                    border: `1px solid ${alpha(theme.palette.text.primary, 0.10)}`,
                                    background: alpha("#fff", 0.7),
                                    transform: open ? "rotate(180deg)" : "rotate(0deg)",
                                    transition: "transform 160ms ease",
                                    flex: "0 0 auto",
                                }}
                                aria-hidden
                            >
                                <Box
                                    sx={{
                                        width: 0,
                                        height: 0,
                                        borderLeft: "6px solid transparent",
                                        borderRight: "6px solid transparent",
                                        borderTop: `7px solid ${alpha(theme.palette.text.primary, 0.55)}`,
                                    }}
                                />
                            </Box>
                        </Stack>
                    </Box>

                    {/* Popover / Lightbox direkt unter der Karte */}
                    <Popper
                        open={open}
                        anchorEl={anchorRef.current}
                        placement="bottom-start"
                        disablePortal={false}
                        modifiers={[
                            { name: "offset", options: { offset: [0, 10] } },
                            { name: "preventOverflow", options: { padding: 12 } },
                        ]}
                        style={{ zIndex: 1500 }}
                    >
                        <Grow in={open} timeout={170}>
                            <Box
                                sx={{
                                    width: { xs: "calc(100vw - 32px)", sm: 420 },
                                    maxWidth: 520,
                                    borderRadius: 3,
                                    p: 2,
                                    background: alpha("#FFFFFF", 0.92),
                                    border: `1px solid ${alpha(theme.palette.text.primary, 0.10)}`,
                                    boxShadow: "0 24px 80px rgba(11,27,36,0.22)",
                                    backdropFilter: "blur(12px)",
                                }}
                            >
                                <Stack direction="row" spacing={1.4} alignItems="center">
                                    {/* Initialen-Kreis (immer, auch wenn Bild existiert) */}
                                    <Box
                                        sx={{
                                            width: 44,
                                            height: 44,
                                            borderRadius: 999,
                                            display: "grid",
                                            placeItems: "center",
                                            background: alpha(theme.palette.primary.main, 0.08),
                                            border: `1px solid ${alpha(theme.palette.primary.main, 0.16)}`,
                                            flex: "0 0 auto",
                                        }}
                                    >
                                        <Typography sx={{ fontWeight: 950, letterSpacing: 0.5 }}>
                                            {initials}
                                        </Typography>
                                    </Box>

                                    <Box sx={{ minWidth: 0 }}>
                                        <Typography variant="h6" sx={{ fontWeight: 950, lineHeight: 1.15 }}>
                                            {name}
                                        </Typography>

                                        {/* Chips oder Rolle */}
                                        {chips.length > 0 ? (
                                            <Stack direction="row" spacing={1} useFlexGap flexWrap="wrap" sx={{ mt: 0.7 }}>
                                                {chips.map((c) => (
                                                    <Chip
                                                        key={c}
                                                        size="small"
                                                        label={c}
                                                        sx={{
                                                            fontWeight: 750,
                                                            background: alpha(theme.palette.primary.main, 0.08),
                                                            border: `1px solid ${alpha(theme.palette.primary.main, 0.16)}`,
                                                        }}
                                                    />
                                                ))}
                                            </Stack>
                                        ) : (
                                            <Typography sx={{ color: "text.secondary", lineHeight: 1.5 }}>
                                                {role}
                                            </Typography>
                                        )}
                                    </Box>
                                </Stack>

                                <Box
                                    sx={{
                                        mt: 2,
                                        display: "flex",
                                        justifyContent: "center",
                                    }}
                                >
                                    <AvatarCircle
                                        src={src}
                                        alt={name}
                                        size={150} // <-- einfach größer als oben
                                        label={!src ? initials : undefined}
                                        icon={icon}
                                    />
                                </Box>
                            </Box>
                        </Grow>
                    </Popper>
                </Box>
            </ClickAwayListener>
        );
    };

    const [pressArticles, setPressArticles] = useState([]);
    const [lakeImages, setLakeImages] = useState([]);

    const tabs = useMemo(
        () => [
            { label: "Über uns", key: "about", icon: <HistoryEdu /> },
            { label: "Ansprechpartner", key: "ansprechpartner", icon: <Badge /> },
            { label: "Mitgliedschaft", key: "mitgliedschaft", icon: <Savings /> },
            { label: "Presse", key: "presse", icon: <PhotoLibrary /> },
            { label: "Vereinssee", key: "vereinssee", icon: <Waves /> },
        ],
        []
    );

    const [currentTab, setCurrentTab] = useState("about");

    useEffect(() => {
        fetch(process.env.PUBLIC_URL + "/resources/presse/articles.json")
            .then((res) => (res.ok ? res.json() : []))
            .then((data) =>
                setPressArticles((data || []).map((file) => ({
                    name: file,
                    url: process.env.PUBLIC_URL + `/resources/presse/${file}`,
                })))
            )
            .catch(() => setPressArticles([]));

        fetch(process.env.PUBLIC_URL + "/resources/vereinssee/images.json")
            .then((res) => (res.ok ? res.json() : []))
            .then((data) => setLakeImages((data || []).map((file) => process.env.PUBLIC_URL + `/resources/vereinssee/${file}`)))
            .catch(() => setLakeImages([]));
    }, []);

    if (error) return <div style={{ padding: 16 }}>Fehler: {error}</div>;
    if (!content) return <div style={{ padding: 16 }}>Lade Inhalte…</div>;

    const SectionTitle = ({ icon, title, subtitle }) => (
        <Stack direction="row" spacing={1.2} alignItems="center" sx={{ mb: 1.2 }}>
            <Box
                sx={{
                    width: 42,
                    height: 42,
                    borderRadius: 999,
                    display: "grid",
                    placeItems: "center",
                    background: alpha(theme.palette.primary.main, 0.08),
                    border: `1px solid ${alpha(theme.palette.primary.main, 0.16)}`,
                }}
            >
                {icon}
            </Box>
            <Box>
                <Typography variant="h6" sx={{ fontWeight: 900, lineHeight: 1.15 }}>
                    {title}
                </Typography>
                {subtitle ? (
                    <Typography variant="body2" sx={{ color: "text.secondary" }}>
                        {subtitle}
                    </Typography>
                ) : null}
            </Box>
        </Stack>
    );

    const renderTabContent = () => {
        switch (currentTab) {
            case "about":
                return (
                    <Stack spacing={2}>
                        <GlassCard>
                            <SectionTitle
                                icon={<Groups />}
                                title="Tauchsport mit Haltung"
                                subtitle="Gemeinschaft, Sicherheit und die Faszination Unterwasser"
                            />
                            <Typography sx={{ color: "text.secondary", lineHeight: 1.9 }}>
                                Über 50 Jahre Tauchsport Club Wülfrath: Am 15.09.1972 trafen sich zehn begeisterte Taucher in den
                                Privaträumen von Peter Stach in Wülfrath – der Startschuss für einen Verein, der bis heute für
                                fundierte Ausbildung, Spaß am Sport und respektvollen Umgang mit der Natur steht.
                            </Typography>
                            <Divider sx={{ my: 2 }} />
                            <Box sx={{ display: "grid", gridTemplateColumns: { xs: "1fr", md: "1fr 1fr" }, gap: 16 }}>
                                <Box
                                    sx={{
                                        p: 2.2,
                                        borderRadius: 3,
                                        background: alpha(theme.palette.primary.main, 0.04),
                                        border: `1px solid ${alpha(theme.palette.primary.main, 0.10)}`,
                                    }}
                                >
                                    <Typography sx={{ fontWeight: 900, mb: 0.6 }}>Unser Fokus</Typography>
                                    <Typography sx={{ color: "text.secondary", lineHeight: 1.8 }}>
                                        Kein Leistungssport – wir tauchen, um die Vielfalt der Unterwasserwelt und die Schwerelosigkeit zu
                                        erleben. Sicherheit und saubere Technik sind dabei die Basis.
                                    </Typography>
                                </Box>
                                <Box
                                    sx={{
                                        p: 2.2,
                                        borderRadius: 3,
                                        background: alpha(theme.palette.secondary.main, 0.08),
                                        border: `1px solid ${alpha(theme.palette.secondary.main, 0.22)}`,
                                    }}
                                >
                                    <Typography sx={{ fontWeight: 900, mb: 0.6 }}>Ausbildung</Typography>
                                    <Typography sx={{ color: "text.secondary", lineHeight: 1.8 }}>
                                        Wir setzen auf gründliche Ausbildung statt Schnellkurs: vom Einstieg bis zu höheren Brevets – mit
                                        mehreren Tauchlehrern und starkem Jugendbereich.
                                    </Typography>
                                </Box>
                            </Box>
                        </GlassCard>

                        <GlassCard>
                            <SectionTitle icon={<HistoryEdu />} title="Kurzchronik" subtitle="Ein paar Meilensteine" />
                            <Box sx={{ display: "grid", gridTemplateColumns: { xs: "1fr", md: "1fr 1fr 1fr" }, gap: 16 }}>
                                {[
                                    { year: "1972", text: "Gründung durch zehn Taucher in Wülfrath." },
                                    { year: "1973", text: "Eintragung als TSC Niederberg ins Vereinsregister." },
                                    { year: "1974/1975", text: "Umbenennung zu TSC Wülfrath – klarer Bezug zur Heimatgemeinde." },
                                ].map((t) => (
                                    <Box
                                        key={t.year}
                                        sx={{
                                            p: 2.2,
                                            borderRadius: 3,
                                            border: `1px solid ${alpha(theme.palette.text.primary, 0.10)}`,
                                            background: alpha("#fff", 0.6),
                                        }}
                                    >
                                        <Typography sx={{ fontWeight: 950, fontSize: 18 }}>{t.year}</Typography>
                                        <Typography sx={{ color: "text.secondary", lineHeight: 1.7, mt: 0.6 }}>{t.text}</Typography>
                                    </Box>
                                ))}
                            </Box>
                        </GlassCard>
                    </Stack>
                );

            case "ansprechpartner": {
                const vorstand = [
                    {
                        key: "vorsitzender1",
                        role: "1. Vorsitzender",
                        name: content.ansprechpartner.vorsitzender1,
                        icon: <Person />,
                    },
                    {
                        key: "vorsitzender2",
                        role: "2. Vorsitzender",
                        name: content.ansprechpartner.vorsitzender2,
                        icon: <Person />,
                    },
                    {
                        key: "kassierer",
                        role: "Kassierer",
                        name: content.ansprechpartner.kassierer,
                        icon: <Person />,
                    },
                ];

                const splitTrainer = (s) => {
                    const parts = String(s).split("–"); // Gedankenstrich
                    const name = parts[0]?.trim() || String(s).trim();
                    const details = parts.slice(1).join("–").trim(); // Rest (Qualifikationen)
                    return { name, details };
                };

                const trainer =
                    (content.ansprechpartner.trainerUndTl || []).map((line) => {
                        const { name, details } = splitTrainer(line);
                        return {
                            name,
                            role: details ? details : "Trainer / Tauchlehrer",
                            key: `trainer_${slugify(name)}`,
                            icon: <School />,
                        };
                    }) || [];

                const geraetewarte = [
                    {
                        key: "geraetewart1",
                        role: "1. Gerätewart",
                        name: content.ansprechpartner.geraetewart1,
                        icon: <Build />,
                    },
                    {
                        key: "geraetewart2",
                        role: "2. Gerätewart",
                        name: content.ansprechpartner.geraetewart2,
                        icon: <Build />,
                    },
                ];

                return (
                    <Stack spacing={2}>
                        <GlassCard>
                            <SectionTitle icon={<Badge />} title="Vorstand" subtitle="Deine Ansprechpartner im Verein" />
                            <Box sx={{ display: "grid", gridTemplateColumns: { xs: "1fr", md: "1fr 1fr 1fr" }, gap: 16 }}>
                                {vorstand.map((p) => (
                                    <PersonCard key={p.key} name={p.name} role={p.role} imgKey={p.key} icon={p.icon} />
                                ))}
                            </Box>
                        </GlassCard>

                        <GlassCard>
                            <SectionTitle icon={<School />} title="Trainer & Tauchlehrer" subtitle="Ausbildung & Training" />
                            <Box
                                sx={{
                                    display: "grid",
                                    gridTemplateColumns: { xs: "1fr", md: "1fr 1fr" },
                                    gap: 16,
                                }}
                            >
                                {trainer.map((p) => (
                                    <PersonCard key={p.key} name={p.name} role={p.role} imgKey={p.key} icon={p.icon} />
                                ))}
                            </Box>

                            <Divider sx={{ my: 2.4 }} />

                            <SectionTitle icon={<Build />} title="Gerätewarte" subtitle="Technik & Material" />
                            <Box sx={{ display: "grid", gridTemplateColumns: { xs: "1fr", md: "1fr 1fr" }, gap: 16 }}>
                                {geraetewarte.map((p) => (
                                    <PersonCard key={p.key} name={p.name} role={p.role} imgKey={p.key} icon={p.icon} />
                                ))}
                            </Box>
                        </GlassCard>
                    </Stack>
                );
            }

            case "mitgliedschaft":
                return (
                    <Stack spacing={2}>
                        <GlassCard>
                            <SectionTitle icon={<Savings />} title="Mitgliedschaft" subtitle="Training, Community & Vorteile" />
                            <Box sx={{ display: "grid", gridTemplateColumns: { xs: "1fr", md: "1.2fr 0.8fr" }, gap: 16 }}>
                                <Box
                                    sx={{
                                        p: 2.2,
                                        borderRadius: 3,
                                        background: alpha(theme.palette.secondary.main, 0.08),
                                        border: `1px solid ${alpha(theme.palette.secondary.main, 0.22)}`,
                                    }}
                                >
                                    <Typography sx={{ fontWeight: 950, mb: 0.6 }}>Welche Vorteile bietet die Mitgliedschaft?</Typography>
                                    <BulletList items={content.mitgliedschaft.vorteile} />
                                </Box>

                                <Box
                                    sx={{
                                        p: 2.2,
                                        borderRadius: 3,
                                        background: alpha(theme.palette.primary.main, 0.04),
                                        border: `1px solid ${alpha(theme.palette.primary.main, 0.10)}`,
                                    }}
                                >
                                    <Typography sx={{ fontWeight: 950, mb: 0.8 }}>Wie wird man Mitglied?</Typography>
                                    <BulletList items={content.mitgliedschaft.wieWirdManMitglied} />
                                </Box>
                            </Box>
                        </GlassCard>

                        <GlassCard>
                            <SectionTitle icon={<Savings />} title="Mitgliedsbeiträge" />
                            <Typography sx={{ color: "text.secondary", lineHeight: 1.8 }}>
                                Die Aufnahmegebühr entfällt seit Beschluss der Mitgliederversammlung am 22.03.2013.
                            </Typography>

                            <Stack direction="row" rowGap={1} spacing={1} sx={{ flexWrap: "wrap", mt: 1.5 }}>
                                <Chip label={content.mitgliedschaft.beitraege.erwachsene} />
                                <Chip label={content.mitgliedschaft.beitraege.kinder} />
                                <Chip label={content.mitgliedschaft.beitraege.passiv} />
                            </Stack>

                            <Box
                                sx={{
                                    mt: 2,
                                    p: 2,
                                    borderRadius: 3,
                                    border: `1px solid ${alpha(theme.palette.text.primary, 0.10)}`,
                                    background: alpha("#fff", 0.65),
                                }}
                            >
                                <Typography sx={{ color: "text.secondary", lineHeight: 1.8 }}>
                                    Im Beitrag enthalten: Nutzung des Schwimmbads zweimal pro Woche, Versicherungsschutz sowie ein Abo der
                                    Tauchsport-Zeitschrift.
                                </Typography>
                            </Box>

                            <Box
                                sx={{
                                    mt: 2,
                                    p: 2.2,
                                    borderRadius: 3,
                                    background: alpha(theme.palette.secondary.main, 0.08),
                                    border: `1px solid ${alpha(theme.palette.secondary.main, 0.22)}`,
                                    display: "flex",
                                    flexWrap: "wrap",
                                    alignItems: "center",
                                    justifyContent: "space-between",
                                    gap: 1.2,
                                }}
                            >
                                <Typography sx={{ color: "text.secondary", lineHeight: 1.8, maxWidth: 620 }}>
                                    Der Online-Mitgliedsantrag steht dir jederzeit digital zur Verfügung. So kannst du deinen Antrag direkt
                                    und unkompliziert einreichen.
                                </Typography>
                                <Chip
                                    component="a"
                                    clickable
                                    href="https://web.meinverein.de/profile/75580/member-request-application"
                                    target="_blank"
                                    rel="noreferrer"
                                    label="Zum Online-Mitgliedsantrag"
                                    sx={{ fontWeight: 800, px: 0.8 }}
                                />
                            </Box>
                        </GlassCard>
                    </Stack>
                );

            case "presse":
                return (
                    <GlassCard>
                        <SectionTitle icon={<PhotoLibrary />} title="Presse" subtitle="Eine Galerie von Pressemitteilungen" />
                        {pressArticles.length > 0 ? (
                            <PdfGallery files={pressArticles} />
                        ) : (
                            <Box sx={{ p: 2.4, borderRadius: 3, background: alpha(theme.palette.primary.main, 0.04) }}>
                                <Typography sx={{ color: "text.secondary" }}>
                                    Aktuell sind noch keine Presseartikel hinterlegt. Bitte komm bald wieder!
                                </Typography>
                            </Box>
                        )}
                    </GlassCard>
                );

            case "vereinssee": {
                const lakeQuery = encodeURIComponent("Gut Widdauen 2, 40764 Langenfeld");
                const lakeMapUrl = `https://www.google.com/maps?q=${lakeQuery}&output=embed`;
                const lakeOpenUrl = `https://www.google.com/maps/search/?api=1&query=${lakeQuery}`;

                return (
                    <Stack spacing={2}>
                        <GlassCard>
                            <SectionTitle icon={<Waves />} title="Vereinssee" subtitle="Tauchgänge am See Gut Widdauen 2" />
                            <Typography sx={{ color: "text.secondary", lineHeight: 1.85, mb: 2 }}>
                                Für unsere Mitglieder steht der Vereinssee in Langenfeld zur Verfügung. Die Kosten für die
                                Jahrestauchgenehmigung am See Gut Widdauen 2 werden zu 50 % vom Verein getragen.
                            </Typography>

                            {lakeImages.length > 0 ? (
                                <ImageSlideshow images={lakeImages} height={420} altPrefix="Vereinssee" />
                            ) : (
                                <Box sx={{ p: 2.4, borderRadius: 3, background: alpha(theme.palette.primary.main, 0.04), mb: 2 }}>
                                    <Typography sx={{ color: "text.secondary" }}>
                                        Aktuell sind noch keine Bilder des Sees hinterlegt.
                                    </Typography>
                                </Box>
                            )}
                        </GlassCard>

                        <GlassCard sx={{ display: "flex", flexDirection: "column" }}>
                            <SectionTitle icon={<Waves />} title="Lage des Vereinssees" subtitle="Gut Widdauen 2, Langenfeld" />
                            <Button
                                variant="text"
                                href={lakeOpenUrl}
                                target="_blank"
                                rel="noreferrer"
                                sx={{ justifyContent: "flex-start", mb: 1.5 }}
                            >
                                In Google Maps öffnen
                            </Button>
                            <Box
                                sx={{
                                    borderRadius: 3,
                                    overflow: "hidden",
                                    border: `1px solid ${alpha(theme.palette.text.primary, 0.10)}`,
                                    minHeight: { xs: 340, md: 430 },
                                    flexGrow: 1,
                                    display: "grid",
                                    placeItems: "center",
                                    background: alpha(theme.palette.primary.main, 0.03),
                                }}
                            >
                                {!hasExternalConsent ? (
                                    <ExternalContentNotice
                                        title="Google Maps erst nach Einwilligung"
                                        description="Nach deiner Zustimmung wird auch die Karte des Vereinssees direkt geladen."
                                    />
                                ) : (
                                    <iframe
                                        title="Google Maps Vereinssee"
                                        src={lakeMapUrl}
                                        width="100%"
                                        height="100%"
                                        style={{ border: 0, display: "block", minHeight: "100%" }}
                                        loading="lazy"
                                        referrerPolicy="no-referrer-when-downgrade"
                                        allowFullScreen
                                    />
                                )}
                            </Box>
                        </GlassCard>
                    </Stack>
                );
            }

            default:
                return null;
        }
    };

    return (
        <Container maxWidth="lg">
            {/* Header */}
            <Box
                component={motion.div}
                initial={{ opacity: 0, y: 14 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.6 }}
                sx={{ mb: 3 }}
            >
                <Typography variant="h3" sx={{ mb: 1 }}>
                    Über uns
                </Typography>
                <Typography sx={{ color: "text.secondary", maxWidth: 860, lineHeight: 1.8 }}>
                    Ein Verein mit Tradition – und mit modernem Anspruch an Ausbildung, Sicherheit und Gemeinschaft.
                </Typography>

                <Box sx={{ mt: 2.2 }}>
                    <PillTabs value={currentTab} onChange={(_, v) => setCurrentTab(v)} tabs={tabs} />
                </Box>
            </Box>

            {/* Content */}
            <Box sx={{ pb: 2 }}>{renderTabContent()}</Box>
        </Container>
    );
}
